var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"항복! 항복입니다!","JPN":"降伏！　降伏します！","ENG":"Surrender! I surrender!","TWN":"投降！我投降！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"얌전히 교도소로 돌아갈 테니 쏘지만 말아주세요!","JPN":"大人しく刑務所に戻りますから、撃たないでください！","ENG":"I'll go back to prison. Please don't shoot!","TWN":"我會乖乖回監獄的，請別開槍！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"뭐야? 이 음침한 여자는!","JPN":"何だ？　この陰気な女は！","ENG":"Who's this gloomy-looking woman?","TWN":"搞什麼？這個陰沉的女人！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"너한텐 볼 일 없으니 저리 비켜!","JPN":"お前に用はない、どけ！","ENG":"We've got no business with you. Buzz off!","TWN":"這與你無關，給我讓開！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"꺄아악!","JPN":"きゃああっ！","ENG":"Kyaaah!","TWN":"啊啊啊！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"쿠울......","JPN":"すやすや……","ENG":"Zzz...","TWN":"呼呼……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"여기 있었군! 다들, 타겟을 확보했다!","JPN":"ここにいたか！　みんな、ターゲットを確保した！","ENG":"There she is! Guys, I've secured our target!","TWN":"在這裡！確定目標了！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"전투 중단하고 지체 없이 빠져나간다!","JPN":"戦闘を中止してただちに退却するぞ！","ENG":"Let's stop fighting and get out of here now!","TWN":"停止戰鬥，快速撤離現場！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"휴우...... 날 노린게 아니라서 정말 다행이야......","JPN":"ふう……私を狙いに来たんじゃないのか。よかった……","ENG":"Phew! Thank God, they didn't come for me!","TWN":"呼……還好不是來找我的，真是太好了……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"이런! 이디스!","JPN":"しまった！　イーディス！","ENG":"Oh, no! Edith!","TWN":"啊！伊蒂絲！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"......음?","JPN":"……うん？","ENG":"Mm?","TWN":"……嗯？"},"stage":{"bg":"HELI_NORMAL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"쿠울......","JPN":"すやすや……","ENG":"Zzz...","TWN":"呼呼……"},"stage":{"bg":"HELI_NORMAL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저, 저런~! 소녀가 납치를 당하고 있네요. 뭔가 좋은 방법이 없으려나?","JPN":"ど、どうしよう～！　少女が拉致されました。何かいい方法はないですか！","ENG":"Oh, no! They're taking her away! Isn't there anything we can do?","TWN":"哎呀～！那個少女要被綁架了呢，沒有什麼好辦法嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"곤란하네요. 공중은 제 전문 분야가 아닌데......","JPN":"困りましたね。空中は私の専門じゃないので……","ENG":"I don't know. Anti-air warfare is not my specialty.","TWN":"傷腦筋啊，空戰不是我的專門領域的說……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"이럴 때 제 파트너 아가씨가 계셨다면 이렇게 피융~ 하고 한방에......","JPN":"こんな時に、私のパートナーがいたらサクッと一発で……","ENG":"I wish my partner lady was here. With a pop, she could have shot them down at once.","TWN":"如果這種時候有我的搭檔小姐在，''碰''的一下就能……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야? 뭐가 날아온 거야!","JPN":"何だ？　何か飛んで来たぞ！","ENG":"What? What was that?","TWN":"什麼？有什麼東西飛過來了！"},"stage":{"bg":"SKY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HELI_STATE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"장거리 저격이다! 어디서 쏜 건지 알 수가 없어!","JPN":"遠距離狙撃だ！　どこから撃ってきたのかわからない！","ENG":"A long-range sniper shot! I can't tell where it's from!","TWN":"是遠距離狙擊！無法得知是從哪裡射擊的！"},"stage":{"bg":"SKY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HELI_STATE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"엔진이 당했다! 추락한다!","JPN":"エンジンがやられた！　墜落する！","ENG":"Our engine is shot! We're going down!","TWN":"引擎被打中了！要墜落了！"},"stage":{"bg":"SKY","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HELI_STATE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_LOOP"},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"이디스! 괜찮아요?","JPN":"イーディス！　大丈夫ですか？","ENG":"Edith! Are you okay?","TWN":"伊蒂絲！妳還好嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"어풉푸......!","JPN":"あぷぷ……！","ENG":"Poooff, poof!","TWN":"啊噗噗……！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L41_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"흐에엥...... 수영장 물...... 더는 마시기 싫어.","JPN":"ふえぇん……プールの水……これ以上飲みたくないよぉ。","ENG":"Hhhheeeennnggg... I don't want to taste chlorine anymore...","TWN":"唔啊啊……不想再喝……游泳池裡的水了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"쿠울......","JPN":"すやすや……","ENG":"Zzz...","TWN":"呼呼……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"헬기가 수영장으로 떨어져서 다행이네요.","JPN":"ヘリがプールに落ちてよかったですね。","ENG":"I'm glad the chopper fell into the pool.","TWN":"還好直升機是掉進泳池裡。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그런데 이 익숙한 저격 솜씨는 설마?","JPN":"ところで、この見慣れた狙撃の腕前はもしや？","ENG":"By the way, whoever shot them down feels familiar. Can it be...","TWN":"不過這個狙擊實力好熟悉，難道是？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"급박해 보이는 상황이라 좀 과격한 방법을 썼는데......","JPN":"緊急状態のようでしたので、少し過激な方法を使いましたが……","ENG":"The situation looked urgent, so I resorted to a drastic measure.","TWN":"我看情況危急，所以就用了稍微過分的方式……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"다들 무사하신가요?","JPN":"皆さん、無事ですか？","ENG":"Is everyone okay?","TWN":"大家都沒事吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"......어라?","JPN":"……あれ？","ENG":"Oh?","TWN":"……哎呀？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"와아~ 너무 반가워요! 카린 양을 여기서 보게 될 줄이야!","JPN":"わぁ～嬉しいです！　ここでカリンさんに会えるとは！","ENG":"Whoa, Karin! I'm so happy to see you here!","TWN":"哇～我太高興了！沒想到會在這裡遇到卡琳小姐！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"악, 떨어져요, 시영 씨! 축축하니까 떨어지라고!","JPN":"あっ、離れて、シノンさん！　じめじめするから離れてください！","ENG":"Argh, get off me, Shiyoung! You're wet! Get off!","TWN":"啊，離我遠點啦，時雨小姐！妳會弄濕我的衣服啦！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대체 뭐에요! 왜 임무 도중에 홀연히 사라져선 그런 차림으로 여기 있는 거죠?!","JPN":"いったい何なんですか？　なぜ任務中に忽然と消えて、そんな格好でここにいるんですか？","ENG":"What in the blazes happened? How come you're here dressed like that after you disappeared during the mission all of a sudden?","TWN":"到底怎麼回事！妳為什麼在執行任務的時候突然消失，現在這身打扮又是什麼？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"아하하, 이건 그러니까 말이죠.","JPN":"あはは、これはですね。","ENG":"Ah hah hah. I can explain.","TWN":"啊哈哈，這個嘛。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흥, 뭐라 변명할지 뻔하네요.","JPN":"ふん、言わなくてもわかりますよ。","ENG":"Hah, don't bother.","TWN":"哼，妳想說什麼藉口我都猜到了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어쩌다 엉뚱한 곳으로 빨려오게 됐는데, 돌아가는 법을 몰라서 그 유별나게 용병다운 적응력으로 이 상황을 즐기는 편이 낫다고 판단한 거겠죠.","JPN":"偶然変なところに吸い込まれてしまったけど、帰る方法がわからなくて、\\nその傭兵らしいすごい適応力でこの状況を楽しんだほうがいいと判断したんでしょうね。","ENG":"Somehow you were dragged here, and since you didn't know how to go back, you decided to enjoy yourself, like the extremely adaptive mercenary that you are.","TWN":"妳一定是不小心被吸到了什麼奇怪的空間，不知道該怎麼回去，然後就發揮妳那超凡的傭兵適應力，就決定先享受對了，是不是？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"와아~ 이렇게 다시 만난 것도 신기한데 제 생각까지 전부 꿰뚫어보시다니.","JPN":"わぁ～こうして再会したのも不思議ですが、私の考えまで全部見通すなんて。","ENG":"Whoa! Not only did you manage to find me, but you also figured out what happened.","TWN":"哇～在這裡重逢就已經夠神奇了，妳竟然還看穿我的想法。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"역시 이런 걸 두고 천생연분이라고 하는 거죠?","JPN":"やっぱりこういうのを、運命の赤い糸で結ばれた関係と言うんですかね？","ENG":"You and I are a match made in heaven, aren't we?","TWN":"果然，我們這樣就是所謂的天生一對吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"농담 집어치워요! 나 혼자 내버려두고 가버리는 바람에 얼마나 고생했는지 알아?!","JPN":"冗談はやめてください！　私をほったらかして行ってしまったせいで、どれだけ苦労したかわかりますか？","ENG":"Shut it! I almost died because you left me behind!","TWN":"別開玩笑了！妳知道我被丟下後有多辛苦嗎？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"제 의지가 아니었으니 어쩔 수 없는걸요? 그래도 속으론 걱정 많이 했다고요.","JPN":"私の意志じゃなかったんだから、仕方ないでしょう？　これでも、かなり心配してましたよ。","ENG":"I couldn't help it. But I've been really worried about you.","TWN":"我又不是故意的，沒辦法呀。而且我也很擔心妳耶。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"누가 봐도 자기 혼자 휴가를 즐기는 차림을 하고서 잘도 걱정했다는 말이 나오는군요.","JPN":"誰が見ても一人で休暇を楽しむ格好なのに、よくもそんなことが言えますね。","ENG":"You don't look like you're worried. You look like you've been enjoying a vacation.","TWN":"不管是誰來看，妳都是一副獨自來休假的打扮，還好意思說妳擔心我。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"침식체들도 다 같이 빨려왔기에 망정이지, 하마터면 마을이 쑥대밭이 될 뻔했잖아요!","JPN":"ですが、侵食体も一緒に吸い込まれて幸いでした。下手したら町がめちゃくちゃになるところでしたよ！","ENG":"Thank God, the C.O.s came with me. Otherwise, the village would have been razed to the ground.","TWN":"幸虧連侵蝕體也被一起吸過來，不然村子都要變成廢墟了！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"하하...... 죄송합니다.","JPN":"ハハ……すみません。","ENG":"Hah hah... Sorry.","TWN":"哈哈……對不起。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저기...... 두 분은 서로 아는 사이인가요?","JPN":"あの……二人ってお知り合いなんですか？","ENG":"Excuse me. Do you know each other?","TWN":"那個……你們兩位認識嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네? 아, 저희는 그저......","JPN":"はい？　あ、私たちはただ……","ENG":"Huh? Oh, we're just—","TWN":"嗯？啊，我們是……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아앗! 그러고 보니 당신은 로널드 리 박사잖아?!","JPN":"あっ！　そういえば、あなたはロナルド・リー博士じゃないですか！？","ENG":"Ah! You! You're Doctor Ronald Lee!","TWN":"啊啊！你不是羅那魯多·李博士嗎？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어째서 당신까지 이런 곳에 있는 거죠?","JPN":"どうして博士がこんなところにいるんですか？","ENG":"What are you doing here?","TWN":"為什麼連你都在這種地方？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"네, 네? 절 아시나요?","JPN":"え、はい？　私を知ってるんですか？","ENG":"E-excuse me? Do I know you?","TWN":"咦，咦？妳認識我？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니, 그보다 그 모습은 대체...... 당신 여자였어?!","JPN":"いや、それより、その格好はいったい……あなた、女性だったでしょうか？","ENG":"Wait, and you're... Were you a WOMAN?!","TWN":"不過，看妳現在的樣子……原來妳是女的？！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"자, 카린 양. 진정하세요. 우리가 이런 일을 처음 겪어보는 것도 아니잖아요?","JPN":"まぁまぁ、カリンさん。落ち着いてください。初めて経験することでもないでしょう？","ENG":"Now, Karin, please calm down. This isn't the first time we're dragged into a situation like this.","TWN":"好了，卡琳小姐，冷靜一下。我們不是第一次遇到這種事情了吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇게 태연한 마인드를 가진 당신이 특이케이스라는 자각은 있는 건가요?","JPN":"そんなにのんきな考え方を持っているあなたは、変わり者だという自覚はないんですか？","ENG":"I can't believe you're so calm right now. You're something, do you know that?","TWN":"妳知道妳任何時候都不為所動的性格很與眾不同嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우린 원래 있던 곳으로 돌아가야 해요! 지금 당장!","JPN":"私たちは元の場所に帰らなければなりません！　今すぐ！","ENG":"We must go back to where we came from. Right this minute!","TWN":"我們必須回到原來的地方！立刻！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그렇게까지 말씀하시면 저야 따라야죠.","JPN":"そこまで言うなら、帰ってもいいですよ。","ENG":"Okay, if you insist.","TWN":"既然妳都說到這個份上了，我只能聽妳的囉。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그런데, 어떻게 돌아갈지 방법은 아시나요?","JPN":"ところで、帰る方法は知ってますか？","ENG":"But do you know how to?","TWN":"那麼，我們要怎麼回去，這妳知道嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그건......","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"這、這……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"시간이 지나면 알아서 원래 세계로 돌아갈 거라고, <color=#83dcb7>사랑의 마왕님</color>께서 말씀해주셨어요.","JPN":"時間が経つと自然に元の世界に戻れると、<color=#83dcb7>愛の魔王様</color>が言ってました。","ENG":"The <color=#83dcb7>Demon Lord of Love</color> said we'll be sent back to our world if we just wait long enough.","TWN":"之前<color=#83dcb7>愛情魔王</color>大人曾經告訴我，時間一到，我就會回到原來的世界。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그러니까, 우린 그냥 하룻밤 꿈이라 생각하고 편히 즐기면 되는 거라고요.","JPN":"だから、私たちは一晩の夢だと思って、今この瞬間を気楽に楽しめばいいんですよ。","ENG":"So, we might as well enjoy ourselves while we're here, while we can.","TWN":"所以我們就當是在做一場只限一夜的夢，盡情享受就可以了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사랑의...... 마왕? 그게 뭐죠?","JPN":"愛の……魔王？　それは何ですか？","ENG":"The... what? The Demon Lord of Love?","TWN":"愛情……魔王？那是什麼？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"말씀 나누시는 중에 죄송하지만, 적이 또 몰려드는군요.","JPN":"お話し中すみませんが、また敵が襲ってきました。","ENG":"I'm sorry to interrupt you, but more enemies are coming our way.","TWN":"很抱歉打斷你們，但好像又有敵人攻過來了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"아무래도 간단히 물러날 생각은 없는 것 같네요.","JPN":"どうやら簡単には引き下がりそうにないです。","ENG":"I don't think they're going to give up easily.","TWN":"看來對方不會這麼輕易地就撤退呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};